import React, { useState } from "react";
import "./Subscribe.css";
function Subscribe() {
  const [form, setForm] = useState({
    hospitalName: "",
    type: "doctor",
    name: "",
    specialty: "",
    price: "",
    location: "",
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const submit = async () => {
  try {
    const res = await fetch("http://localhost:5000/api/subscription", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify(form)
    });

    const text = await res.text(); // 🔥 get raw response

    let data;
    try {
      data = JSON.parse(text); // try converting to JSON
    } catch {
      throw new Error("Server returned HTML instead of JSON");
    }

    if (!res.ok) {
      throw new Error(data.error || "Something failed");
    }

    alert(data.message);
  } catch (err) {
    alert(err.message);
  }
};

  return (
    <div className="subscribe-page">
  <div className="subscribe-container">
  <h2>Join HEALink Network</h2>
    
  
  <button className="subscribe-btn" onClick={submit}>
    🚀 Submit
  </button>
</div>
</div>
  );
}

export default Subscribe;
